// Simule la réception d'un ticket Mirakl
// En production: remplacer ce noeud par un Webhook Mirakl API
// sessionId format: 'marketplace|country|order_id'
const input = $input.first().json;
const parts = (input.sessionId || 'amazon|FR|demo').split('|');
const mp = parts[0] || 'amazon';
const country = parts[1] || 'FR';
const oid = parts[2] !== 'demo' ? parts[2] : 'ORD-' + Math.floor(Math.random() * 90000 + 10000);

return {
  ticket_id: 'TK-' + Date.now(),
  marketplace: mp,
  country: country,
  order_id: oid,
  client_email: input.client_email || 'client@demo.com',
  client_name: input.client_name || 'Client Demo',
  message: input.chatInput || '',
  subject: input.subject || 'Demande SAV',
  created_at: new Date().toISOString(),
  channel: 'chatbot_demo',
  status: 'nouveau'
};

// Parse et valide le JSON retourné par le Routeur Gemini
const raw = $input.first().json.text || $input.first().json.output || '{}';
let router;
try {
  const cleaned = raw.replace(/```json\n?|```\n?/g, '').trim();
  router = JSON.parse(cleaned);
} catch (e) {
  // Fallback sécurisé si Gemini retourne du JSON invalide
  router = {
    intent: 'autre',
    urgency: 'standard',
    tools_needed: ['lookup_order', 'update_ticket_status'],
    context_sql: `SELECT o.*, c.vip_status FROM orders o LEFT JOIN customers c ON c.email = o.client_email WHERE o.order_id = '${$('📝 Parser Ticket').item.json.order_id}' LIMIT 1`,
    slack_channel: '#sav-standard',
    requires_human: false,
    guardrail_remboursement: false,
    routing_reason: 'Fallback — parsing error Routeur'
  };
}

// Injecter l'order_id réel dans le SQL généré
const orderId = $('📝 Parser Ticket').item.json.order_id;
router.context_sql = (router.context_sql || '')
  .replace('ORDER_ID_ICI', orderId)
  .replace(/order_id = ''/, `order_id = '${orderId}'`);

// Sécurité RB-01 : si message contient remboursement, forcer requires_human
const msg = ($('📝 Parser Ticket').item.json.message || '').toLowerCase();
const remboursementTriggers = ['rembours', 'refund', 'remboursement', 'rembouser'];
if (remboursementTriggers.some(t => msg.includes(t))) {
  router.requires_human = true;
  router.guardrail_remboursement = true;
  router.intent = 'remboursement';
  router.slack_channel = '#sav-escalade';
}

return {
  ...router,
  ticket: $('📝 Parser Ticket').item.json
};

