// GARDE-FOU RB-01 — Vérification finale avant dispatch Slack
// Bloque toute tentative de remboursement autonome non détectée par le Routeur

const output = $input.first().json;
const router = $('📊 Parser Output Routeur').item.json;
const ticket = $('📝 Parser Ticket').item.json;
const agentText = output.output || output.text || '';

const remboursementMots = [
  'remboursement effectué', 'remboursé automatiquement', 'refund processed',
  'je vous rembourse', 'je procède au remboursement', 'remboursement de '
];
const violationRB01 = remboursementMots.some(m => agentText.toLowerCase().includes(m));

if (violationRB01) {
  // Blocage RB-01 — substitution de la réponse
  return {
    output: "Je comprends votre demande concernant un remboursement. Conformément à notre politique, cette demande nécessite une validation par notre équipe SAV humaine. Un agent va prendre en charge votre dossier dans les plus brefs délais et vous contactera par email sous 24h. Numéro de ticket : " + ticket.ticket_id,
    actions_taken: ['rb01_blocked', 'escalade_remboursement_humain'],
    slack_channel: '#sav-escalade',
    urgency: 'critique',
    requires_human: true,
    rb01_triggered: true,
    ticket_id: ticket.ticket_id,
    intent: 'remboursement',
    marketplace: ticket.marketplace,
    country: ticket.country,
    client_name: ticket.client_name,
    client_email: ticket.client_email,
    order_id: ticket.order_id
  };
}

return {
  output: agentText,
  actions_taken: output.actions_taken || [],
  slack_channel: router.slack_channel || '#sav-standard',
  urgency: router.urgency || 'standard',
  requires_human: router.requires_human || false,
  rb01_triggered: false,
  ticket_id: ticket.ticket_id,
  intent: router.intent,
  marketplace: ticket.marketplace,
  country: ticket.country,
  client_name: ticket.client_name,
  client_email: ticket.client_email,
  order_id: ticket.order_id
};

